pub struct Booking {
    pub start: u32,
    pub end: u32,
}

pub fn can_book(existing: &[Booking], requested: Booking) -> bool {
    if requested.start > requested.end {
        return false;
    }

    for b in existing {
        if requested.start <= b.end && b.start <= requested.end {
            return false;
        }
    }

    true
}

