#[derive(Debug, PartialEq, Eq)]
pub struct Entry {
    pub key: String,
    pub value: String,
    pub flags: Vec<String>,
}

pub fn parse_entries(input: &str) -> Result<Vec<Entry>, String> {
    let mut out = Vec::new();
    for (idx, raw) in input.lines().enumerate() {
        let line_no = idx + 1;
        let line = raw.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }

        let parts: Vec<&str> = line.split(';').collect();
        if parts.len() != 3 {
            return Err(format!("line {}: expected 3 fields", line_no));
        }

        let key = parts[0].trim();
        let value = parts[1].trim();
        let flags_raw = parts[2].trim();

        if key.is_empty() || !key.chars().all(|c| c.is_ascii_alphanumeric() || c == '_') {
            return Err(format!("line {}: invalid key", line_no));
        }

        if value.is_empty() {
            return Err(format!("line {}: empty value", line_no));
        }

        let flags = if flags_raw.is_empty() {
            Vec::new()
        } else {
            flags_raw
                .split(',')
                .map(|s| s.trim().to_string())
                .collect()
        };

        out.push(Entry {
            key: key.to_string(),
            value: value.to_string(),
            flags,
        });
    }
    Ok(out)
}

