use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Event {
    Create,
    Start,
    Resolve,
    Reopen,
}

fn apply(state: &str, event: Event) -> String {
    match (state, event) {
        ("Missing", Event::Create) => "Open".to_string(),
        ("Open", Event::Start) => "InProgress".to_string(),
        ("InProgress", Event::Resolve) => "Open".to_string(),
        ("Closed", Event::Reopen) => "Closed".to_string(),
        _ => state.to_string(),
    }
}

fn main() {
    let log = vec![
        ("A", Event::Create),
        ("A", Event::Start),
        ("A", Event::Resolve),
        ("B", Event::Create),
        ("C", Event::Create),
        ("C", Event::Start),
    ];

    let mut states: BTreeMap<&str, String> = BTreeMap::new();

    for (id, event) in log {
        let current = states.get(id).map(|s| s.as_str()).unwrap_or("Missing");
        let next = apply(current, event);
        states.insert(id, next);
    }

    for (id, state) in states {
        println!("{}:{}", id, state);
    }
}

