enum Channel {
    Queue,
    Webhook,
    Email,
}

enum Outcome {
    Delivered(Channel),
    Retry(Channel),
    Dropped { channel: Channel, permanent: bool },
}

fn summarize(items: &[Outcome]) -> String {
    let mut ok = 0;
    let mut retry = 0;
    let mut drop_count = 0;
    let mut queue = 0;
    let mut email = 0;

    for item in items {
        match item {
            Outcome::Delivered(channel) => {
                ok += 1;
                match channel {
                    Channel::Queue => queue += 1,
                    Channel::Webhook => queue += 1,
                    Channel::Email => queue += 1,
                }
            }
            Outcome::Retry(channel) => {
                ok += 1;
                match channel {
                    Channel::Queue => queue += 1,
                    Channel::Webhook => {}
                    Channel::Email => email += 1,
                }
            }
            Outcome::Dropped { channel, permanent } => {
                if *permanent {
                    drop_count += 1;
                } else {
                    retry += 1;
                }
                match channel {
                    Channel::Queue => {}
                    Channel::Webhook => queue += 1,
                    Channel::Email => queue += 1,
                }
            }
        }
    }

    format!(
        "ok={}\nretry={}\ndrop={}\nqueue={}\nemail={}",
        ok, retry, drop_count, queue, email
    )
}

fn main() {
    let items = [
        Outcome::Delivered(Channel::Queue),
        Outcome::Delivered(Channel::Webhook),
        Outcome::Retry(Channel::Queue),
        Outcome::Retry(Channel::Email),
        Outcome::Dropped {
            channel: Channel::Webhook,
